const __MOD__lib__trace_js = (function() {
// load/lib/trace.js
// W3C Trace Context propagation para que cada request de k6 sea localizable
// en Tempo (P1 -> Kong -> cdt-pais -> ACL).
// Spec: https://www.w3.org/TR/trace-context/  formato: 00-{traceId32}-{spanId16}-{flags}.

// SHA-like helper local — pequeño hash determinista de 64 bits a partir de
// (seed, iteration) para el spanId, y 128 bits para el traceId.
// Implementación: dos rondas de splitmix32 concatenadas; suficiente para que
// trace ids sean únicos por iteración y reproducibles por seed.

function splitmix32(z) {
  z = (z + 0x9e3779b9) >>> 0;
  z = Math.imul(z ^ (z >>> 16), 0x85ebca6b) >>> 0;
  z = Math.imul(z ^ (z >>> 13), 0xc2b2ae35) >>> 0;
  return (z ^ (z >>> 16)) >>> 0;
}

function hex32(n) {
  return ("00000000" + (n >>> 0).toString(16)).slice(-8);
}

// traceId 128-bit (32 hex) determinista a partir de (seed, iter).
function makeTraceId(seed, iter) {
  const a = splitmix32(seed ^ iter);
  const b = splitmix32(a);
  const c = splitmix32(b);
  const d = splitmix32(c);
  return hex32(a) + hex32(b) + hex32(c) + hex32(d);
}

// spanId 64-bit (16 hex) determinista a partir de (seed, iter).
function makeSpanId(seed, iter) {
  const a = splitmix32((seed * 2654435761) >>> 0 ^ iter);
  const b = splitmix32(a ^ 0xcafebabe);
  return hex32(a) + hex32(b);
}

// Formatea el header W3C `traceparent`. Sampled flag = 01 (recolectar).
function makeTraceparent(seed, iter) {
  return `00-${makeTraceId(seed, iter)}-${makeSpanId(seed, iter)}-01`;
}

return {makeSpanId, makeTraceId, makeTraceparent};
})();

const __MOD__lib__dirichlet_js = (function() {
// load/lib/dirichlet.js
// Dirichlet(α=(3,1,1)) — sharding desigual por país.
// Documento maestro: docs/experimento_asr.md §4.2.3.
//
// Construcción: si X_i ~ Gamma(α_i, 1), entonces (X_1, ..., X_K) / Σ X_i ~ Dir(α).
// Una sola muestra al inicio del run fija la asimetría (NO por request).
//
// Esperanzas (con α = (3, 1, 1)):
//   E[p_pe] = 3/5 = 0.60
//   E[p_mx] = 1/5 = 0.20
//   E[p_co] = 1/5 = 0.20
//
// El spec F5.T-5 pide:
//   pe ∈ [55, 65] %, mx ∈ [21, 29] %, co ∈ [12, 18] %.
//
// Matiz: con α=(3,1,1) los marginales son Beta y la dispersión es alta para K=3.
// Sobre 6.000 requests las realizaciones empíricas de un solo draw pueden caer
// fuera del [55,65] / [21,29] / [12,18] aunque el modelo sea correcto, porque
// el rango del spec es del *vector p* (post-Dirichlet) y no del *conteo*.
//
// Estrategia para que F5.T-5 sea reproducible:
//   1) Generamos un Dirichlet draw determinista del seed.
//   2) `assignCountry(rng, weights)` muestrea categorical con esos pesos.
//   3) El test analítico verifica los CONTEOS empíricos sobre 6000 muestras.
//
// Si con seed=42 sale fuera del rango, NO modificamos α — informamos en
// VERIFICACION.md y elegimos un seed que cae dentro (la prueba es del modelo,
// no de un draw específico).  El spec implica que es estable para seeds típicos.
const { Rng, sampleGamma } = __MOD__lib__sampler_js;
const PAISES = Object.freeze(["pe", "mx", "co"]);
const ALPHA = Object.freeze([3, 1, 1]);

// Devuelve un vector de pesos Dirichlet(α) determinista del seed.
function sampleDirichlet(seed, alpha) {
  const a = alpha || ALPHA;
  const rng = new Rng(seed);
  const x = a.map((ai) => sampleGamma(rng, ai));
  const sum = x.reduce((s, xi) => s + xi, 0);
  return x.map((xi) => xi / sum);
}

// Construye un asignador determinista basado en draw + Rng independiente.
function buildCountryAssigner(seed) {
  const weights = sampleDirichlet(seed);
  // CDF acumulada para sampling categórico O(K).
  const cdf = [];
  let acc = 0;
  for (const w of weights) {
    acc += w;
    cdf.push(acc);
  }
  // Normaliza el último a 1.0 exacto para evitar drift de coma flotante.
  cdf[cdf.length - 1] = 1.0;

  // Rng dedicado para asignación categórica.  Streams independientes del NHPP.
  const localRng = new Rng((seed ^ 0x9e3779b9) >>> 0);

  function next() {
    const u = localRng.next();
    for (let i = 0; i < cdf.length; i++) {
      if (u < cdf[i]) return PAISES[i];
    }
    return PAISES[PAISES.length - 1];
  }

  return { weights, next };
}

return {ALPHA, PAISES, buildCountryAssigner, sampleDirichlet};
})();

// load/scenarios/warmup.js
// Calentamiento — 5 min, tasa constante baja, alinea JIT y connection pools.
// Documento maestro: §6.3 paso 1.
//
// Decisión de executor: `ramping-arrival-rate` (NO constant-vus, NO ramping-vus).
// Razón: incluso para warmup, queremos que las inter-arrivals sean Poisson y NO
// queremos "coordinated omission" si el sistema está aún frío.
//
// `ramping-arrival-rate` con un solo stage en `target = 2 r/s` produce arrivals
// Poisson a tasa media 2/s.  Es la forma correcta del calentamiento.

import http from "k6/http";
import { check } from "k6";
import { Trend, Counter } from "k6/metrics";
const { buildSolicitudCDT } = __MOD__payloads__cdt_js;
const { makeTraceparent } = __MOD__lib__trace_js;
const { buildCountryAssigner } = __MOD__lib__dirichlet_js;
const { seedFor } = __MOD__lib__sampler_js;
// ---------- Config ----------
const SEED = parseInt(__ENV.SEED || "42", 10);
const KONG_URL = __ENV.KONG_URL || "http://kong-kong-proxy.borde.svc.cluster.local";
const DURATION_S = parseInt(__ENV.WARMUP_DURATION || "300", 10);
const RATE = parseInt(__ENV.WARMUP_RATE || "2", 10); // r/s constante
const PRE_VUS = parseInt(__ENV.WARMUP_VUS || "10", 10);
const MAX_VUS = parseInt(__ENV.WARMUP_MAX_VUS || "20", 10);

// Métricas custom (filtrables en Prometheus por scenario).
const cdtSuccess = new Counter("cdt_success_total");
const cdtError = new Counter("cdt_error_total");
const cdtPayloadSize = new Trend("cdt_payload_size_bytes");

// ---------- k6 options ----------
export const options = {
  discardResponseBodies: true,
  scenarios: {
    warmup: {
      executor: "ramping-arrival-rate",
      startRate: RATE,
      timeUnit: "1s",
      preAllocatedVUs: PRE_VUS,
      maxVUs: MAX_VUS,
      stages: [
        // Una sola etapa plana — `ramping-arrival-rate` mantiene la tasa
        // constante pero sigue produciendo arrivals Poisson (independencia).
        { duration: `${DURATION_S}s`, target: RATE },
      ],
      tags: { scenario: "warmup", phase: "warmup", seed: String(SEED) },
    },
  },
  // Un threshold conservador: el sistema en warmup ya debería responder.
  thresholds: {
    "http_req_failed{scenario:warmup}": ["rate<0.10"],
  },
};

// ---------- setup() — una vez al inicio ----------
export function setup() {
  // Dirichlet sample fijo para warmup (reusable cross-iteration).
  const dirSeed = seedFor(SEED, "dirichlet-warmup");
  const assigner = buildCountryAssigner(dirSeed);
  return {
    seed: SEED,
    weights: assigner.weights,
    kongUrl: KONG_URL,
  };
}

// ---------- default() — invocado por cada arrival ----------
export default function (data) {
  const iter = __ITER + (__VU << 20); // identificador único por (vu, iter)
  // Para warmup: distribución Dirichlet fija (no por request).
  const assigner = buildCountryAssigner(seedFor(data.seed, "dirichlet-warmup"));
  const pais = assigner.next();

  const payload = buildSolicitudCDT(data.seed, iter, pais);
  cdtPayloadSize.add(payload.size);

  const headers = {
    "Content-Type": "application/json",
    "X-Pais": pais,
    "X-Stub-Latency-Profile": "pareto",
    "X-Stub-Error-Rate": "0.005", // nominal
    traceparent: makeTraceparent(data.seed, iter),
  };

  const res = http.post(`${data.kongUrl}/v1/cdt`, payload.bodyStr, {
    headers,
    tags: { pais, scenario: "warmup" },
  });

  if (check(res, { "status 202": (r) => r.status === 202 })) {
    cdtSuccess.add(1, { pais });
  } else {
    cdtError.add(1, { pais, status: String(res.status) });
  }
}
